create extension if not exists pgcrypto;
create type app_role as enum ('admin','participant');
create type participant_status as enum ('pending','active','blocked');
create type round_status as enum ('draft','published','closed','scored');
create type pick_value as enum ('1','X','2');

create table teams(id uuid primary key default gen_random_uuid(), name text not null unique, color text, created_at timestamptz default now());
create table profiles(id uuid primary key references auth.users(id) on delete cascade, email text not null unique, display_name text not null, role app_role not null default 'participant', participant_status participant_status not null default 'pending', team_id uuid references teams(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table participants(id uuid primary key default gen_random_uuid(), profile_id uuid unique references profiles(id) on delete cascade, display_name text not null, official boolean not null default false, status participant_status not null default 'pending', created_at timestamptz default now());
create table team_members(team_id uuid references teams(id) on delete cascade, participant_id uuid references participants(id) on delete cascade, primary key(team_id,participant_id));
create table rounds(id uuid primary key default gen_random_uuid(), number int not null unique, name text not null, status round_status not null default 'draft', published_at timestamptz, deadline_at timestamptz not null, previous_copita_participant_id uuid references participants(id), closed_at timestamptz, scored_at timestamptz, created_at timestamptz default now());
create table matches(id uuid primary key default gen_random_uuid(), round_id uuid not null references rounds(id) on delete cascade, match_order int not null check(match_order between 1 and 14), competition text not null, home_team text not null, away_team text not null, starts_at timestamptz not null, division text not null check(division in ('primera','segunda')), is_pleno boolean not null default false, result pick_value, pleno_score text, unique(round_id,match_order));
create table round_qualified_participants(round_id uuid references rounds(id) on delete cascade, participant_id uuid references participants(id) on delete cascade, primary key(round_id,participant_id));
create table predictions(id uuid primary key default gen_random_uuid(), round_id uuid not null references rounds(id) on delete cascade, participant_id uuid not null references participants(id) on delete cascade, is_default boolean not null default false, submitted_at timestamptz default now(), updated_at timestamptz default now(), unique(round_id,participant_id));
create table prediction_items(prediction_id uuid references predictions(id) on delete cascade, match_id uuid references matches(id) on delete cascade, pick pick_value not null, highlighted boolean not null default false, pleno_score text, primary key(prediction_id,match_id));
create table season_predictions(id uuid primary key default gen_random_uuid(), participant_id uuid not null unique references participants(id) on delete cascade, double_category text not null, submitted_at timestamptz default now(), updated_at timestamptz default now());
create table season_prediction_items(id uuid primary key default gen_random_uuid(), season_prediction_id uuid references season_predictions(id) on delete cascade, category text not null, position int, value text not null);
create table round_scores(round_id uuid references rounds(id) on delete cascade, participant_id uuid references participants(id) on delete cascade, regular_points numeric not null default 0, pleno_points numeric not null default 0, total_points numeric not null default 0, segunda_hits int not null default 0, away_hits int not null default 0, draw_hits int not null default 0, rank int, is_default boolean default false, eliminated boolean default false, saved_by_copita boolean default false, primary key(round_id,participant_id));
create table season_scores(participant_id uuid primary key references participants(id) on delete cascade, points int not null default 0, calculated_at timestamptz default now());
create table money_winnings(profile_id uuid primary key references profiles(id) on delete cascade, amount numeric not null default 0, notes text, updated_at timestamptz default now());
create table tie_break_resolutions(id uuid primary key default gen_random_uuid(), round_id uuid references rounds(id) on delete cascade, participant_id uuid references participants(id), manual_order int not null, reason text, created_by uuid references profiles(id), created_at timestamptz default now());
create table standings(participant_id uuid primary key references participants(id) on delete cascade, total_points numeric default 0, round_points numeric default 0, season_points numeric default 0, copita_count int default 0, money_won numeric default 0, status text default 'active');
create table audit_logs(id bigserial primary key, actor uuid references profiles(id), action text not null, entity text not null, entity_id uuid, payload jsonb, created_at timestamptz default now());

create index idx_profiles_email on profiles(email); create index idx_profiles_status on profiles(participant_status); create index idx_matches_round on matches(round_id); create index idx_predictions_round_participant on predictions(round_id,participant_id); create index idx_scores_round_rank on round_scores(round_id,rank); create index idx_audit_entity on audit_logs(entity,entity_id);

create or replace function is_admin() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from profiles where id=auth.uid() and role='admin') $$;
create or replace function is_active_profile(profile_uuid uuid) returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from profiles where id=profile_uuid and participant_status='active') $$;
create or replace function season_prediction_deadline() returns timestamptz language sql immutable as $$ select '2026-08-14 12:00:00+00'::timestamptz $$;
create or replace function handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into profiles(id,email,display_name,role,participant_status) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'display_name', split_part(new.email,'@',1)),'participant','pending'); insert into participants(profile_id,display_name,official,status) values(new.id,coalesce(new.raw_user_meta_data->>'display_name', split_part(new.email,'@',1)),false,'pending'); insert into money_winnings(profile_id,amount) values(new.id,0); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute function handle_new_user();
create or replace function sync_participant_from_profile() returns trigger language plpgsql security definer set search_path=public as $$ begin update participants set display_name=new.display_name,status=new.participant_status,official=(new.participant_status='active') where profile_id=new.id; return new; end; $$;
create trigger on_profile_updated after update of display_name,participant_status on profiles for each row execute function sync_participant_from_profile();
create or replace function protect_profile_admin_fields() returns trigger language plpgsql security definer set search_path=public as $$ begin if not is_admin() then new.role := old.role; new.participant_status := old.participant_status; new.team_id := old.team_id; end if; new.updated_at := now(); return new; end; $$;
create trigger on_profile_protect_admin_fields before update on profiles for each row execute function protect_profile_admin_fields();

alter table profiles enable row level security; alter table teams enable row level security; alter table participants enable row level security; alter table team_members enable row level security; alter table rounds enable row level security; alter table matches enable row level security; alter table round_qualified_participants enable row level security; alter table predictions enable row level security; alter table prediction_items enable row level security; alter table season_predictions enable row level security; alter table season_prediction_items enable row level security; alter table round_scores enable row level security; alter table season_scores enable row level security; alter table standings enable row level security; alter table money_winnings enable row level security; alter table tie_break_resolutions enable row level security; alter table audit_logs enable row level security;

create policy profiles_select_own_or_admin on profiles for select using(id=auth.uid() or is_admin());
create policy profiles_update_own_basic on profiles for update using(id=auth.uid()) with check(id=auth.uid());
create policy profiles_admin_all on profiles for all using(is_admin()) with check(is_admin());
create policy read_teams on teams for select using(auth.uid() is not null); create policy admin_teams on teams for all using(is_admin()) with check(is_admin());
create policy read_participants on participants for select using(auth.uid() is not null); create policy admin_participants on participants for all using(is_admin()) with check(is_admin());
create policy read_team_members on team_members for select using(auth.uid() is not null); create policy admin_team_members on team_members for all using(is_admin()) with check(is_admin());
create policy read_published_rounds on rounds for select using(status <> 'draft' or is_admin()); create policy admin_rounds on rounds for all using(is_admin()) with check(is_admin());
create policy read_matches on matches for select using(exists(select 1 from rounds r where r.id=round_id and (r.status <> 'draft' or is_admin()))); create policy admin_matches on matches for all using(is_admin()) with check(is_admin());
create policy read_round_qualified on round_qualified_participants for select using(auth.uid() is not null); create policy admin_round_qualified on round_qualified_participants for all using(is_admin()) with check(is_admin());
create policy read_predictions_visibility on predictions for select using(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid()) or exists(select 1 from rounds r where r.id=round_id and now()>=r.deadline_at));
create policy write_active_predictions_before_deadline on predictions for all using(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid() and p.status='active') and is_active_profile(auth.uid()) and exists(select 1 from rounds r join round_qualified_participants q on q.round_id=r.id where r.id=round_id and q.participant_id=participant_id and r.status='published' and now()<r.deadline_at)) with check(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid() and p.status='active') and is_active_profile(auth.uid()));
create policy read_prediction_items_visibility on prediction_items for select using(exists(select 1 from predictions pr where pr.id=prediction_id and (is_admin() or pr.participant_id in (select p.id from participants p where p.profile_id=auth.uid()) or exists(select 1 from rounds r where r.id=pr.round_id and now()>=r.deadline_at))));
create policy write_prediction_items_before_deadline on prediction_items for all using(exists(select 1 from predictions pr join rounds r on r.id=pr.round_id join participants p on p.id=pr.participant_id where pr.id=prediction_id and (is_admin() or p.profile_id=auth.uid() and p.status='active' and is_active_profile(auth.uid()) and r.status='published' and now()<r.deadline_at))) with check(true);
create policy season_predictions_read on season_predictions for select using(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid()) or now()>=season_prediction_deadline());
create policy season_predictions_write on season_predictions for all using(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid() and p.status='active') and is_active_profile(auth.uid()) and now()<season_prediction_deadline()) with check(is_admin() or participant_id in (select p.id from participants p where p.profile_id=auth.uid() and p.status='active') and is_active_profile(auth.uid()));
create policy season_items_read on season_prediction_items for select using(exists(select 1 from season_predictions sp where sp.id=season_prediction_id and (is_admin() or sp.participant_id in (select p.id from participants p where p.profile_id=auth.uid()) or now()>=season_prediction_deadline())));
create policy season_items_write on season_prediction_items for all using(exists(select 1 from season_predictions sp join participants p on p.id=sp.participant_id where sp.id=season_prediction_id and (is_admin() or p.profile_id=auth.uid() and p.status='active' and is_active_profile(auth.uid()) and now()<season_prediction_deadline()))) with check(true);
create policy read_scores on round_scores for select using(auth.uid() is not null); create policy admin_scores on round_scores for all using(is_admin()) with check(is_admin());
create policy read_season_scores on season_scores for select using(auth.uid() is not null); create policy admin_season_scores on season_scores for all using(is_admin()) with check(is_admin());
create policy read_standings on standings for select using(auth.uid() is not null); create policy admin_standings on standings for all using(is_admin()) with check(is_admin());
create policy money_own_or_admin on money_winnings for select using(profile_id=auth.uid() or is_admin()); create policy admin_money on money_winnings for all using(is_admin()) with check(is_admin());
create policy admin_ties on tie_break_resolutions for all using(is_admin()) with check(is_admin()); create policy admin_audit on audit_logs for select using(is_admin()); create policy insert_audit on audit_logs for insert with check(is_admin());
